mapper.select:
select MAX(currency_id) as currencyId , MAX(item_id) as itemId , MAX(chain_tag) as chainTag , MAX(plate_code) as plateCode , MAX(plate_name_zh) as plateNameZh , MAX(plate_name_en) as plateNameEn , MAX(plate_name_ko) as plateNameKo , MAX(plate_name_pt) as plateNamePt
, MAX(plate_name_vi) as plateNameVi , MAX(plate_name_tr) as plateNameTr , MAX(plate_name_tw) as plateNameTw , MAX(plate_name_ja) as plateNameJa , MAX(plate_name_hi) as plateNameHi , MAX(plate_name_th) as plateNameTh , MAX(plate_name_ru) as plateNameRu , MAX(plate_name_ar) as plateNameAr
, ifnull(sum(bet_amount), 0.0000) as betAmount , ifnull(sum(bet_num), 0) as betNum , ifnull(sum(bet_people_num), 0) as betPeopleNum , ifnull(sum(settle_amount), 0.0000) as settleAmount , ifnull(sum(win_lose_amount), 0.0000) as winLoseAmount , ifnull(sum(efficient_bet_amount), 0.0000) as efficientBetAmount , MAX(calculations_time) as calculationsTime , ifnull(sum(code_amount), 0) as codeAmount , ifnull(sum(game_cost), 0) as gameCost , ifnull(sum(game_cost_merchant), 0) as gameCostMerchant from `t_game_plate_count_order` where 1 = 1
and currency_id=#{currencyId}
and day_str >= #{startTime}
and day_str <= #{endTime}
and plate_code = #{plateCode}
AND plate_code in
#{plateCode}

select left (day_str, 7) as dayStr , MAX(currency_id) as currencyId , MAX(item_id) as itemId , MAX(chain_tag) as chainTag , MAX(plate_code) as plateCode , MAX(plate_name_zh) as plateNameZh , MAX(plate_name_en) as plateNameEn , MAX(plate_name_ko) as plateNameKo , MAX(plate_name_pt) as plateNamePt , MAX(plate_name_vi) as plateNameVi , MAX(plate_name_tr) as plateNameTr , MAX(plate_name_tw) as plateNameTw , MAX(plate_name_ja) as plateNameJa , MAX(plate_name_hi) as plateNameHi , MAX(plate_name_th) as plateNameTh , MAX(plate_name_ru) as plateNameRu , MAX(plate_name_ar) as plateNameAr , ifnull(sum(bet_amount), 0.0000) as betAmount , ifnull(sum(bet_num), 0) as betNum , ifnull(sum(bet_people_num), 0) as betPeopleNum , ifnull(sum(settle_amount), 0.0000) as settleAmount , ifnull(sum(win_lose_amount), 0.0000) as winLoseAmount , ifnull(sum(efficient_bet_amount), 0.0000) as efficientBetAmount , MAX(calculations_time) as calculationsTime , ifnull(sum(code_amount), 0) as codeAmount , MAX(create_time) as createTime , MAX(update_time) as updateTime , ifnull(sum(game_cost), 0) as gameCost , ifnull(sum(game_cost_merchant), 0) as gameCostMerchant from t_game_plate_count_order where 1 = 1 and currency_id = #{currencyId} and plate_code = #{plateCode}
and day_str >= #{startTime}
and day_str <= #{endTime}
group by left (day_str, 7);

select plate_code AS plateCode, MAX(LEFT(day_str, 7)) AS dayStr, MAX(currency_id) AS currencyId, MAX(item_id) AS itemId, MAX(chain_tag) AS chainTag, MAX(plate_name_zh) AS plateNameZh, MAX(plate_name_en) AS plateNameEn, MAX(plate_name_ko) as plateNameKo, MAX(plate_name_pt) as plateNamePt, MAX(plate_name_vi) as plateNameVi, MAX(plate_name_tr) as plateNameTr, MAX(plate_name_tw) as plateNameTw, MAX(plate_name_ja) as plateNameJa, MAX(plate_name_hi) as plateNameHi, MAX(plate_name_th) as plateNameTh, MAX(plate_name_ru) as plateNameRu, MAX(plate_name_ar) as plateNameAr, IFNULL(SUM(bet_amount), 0.0000) AS betAmount, IFNULL(SUM(bet_num), 0) AS betNum, IFNULL(SUM(bet_people_num), 0) AS betPeopleNum, IFNULL(SUM(settle_amount), 0.0000) AS settleAmount, IFNULL(SUM(win_lose_amount), 0.0000) AS winLoseAmount, IFNULL(SUM(efficient_bet_amount), 0.0000) AS efficientBetAmount, MAX(calculations_time) AS calculationsTime, IFNULL(SUM(code_amount), 0) AS codeAmount, MAX(create_time) AS createTime, MAX(update_time) AS updateTime, IFNULL(SUM(game_cost), 0) AS gameCost, IFNULL(SUM(game_cost_merchant), 0) AS gameCostMerchant FROM t_game_plate_count_order WHERE currency_id = #{currencyId}
and day_str >= #{startTime}
and day_str <= #{endTime}
AND plate_code in
#{plateCode}
GROUP BY plate_code ORDER BY plate_code;

